import{_ as e}from"./chunks/image-20220920185724360.97a320df.js";import{_ as t,c as T,o as r,a}from"./app.80fd0906.js";const i="/assets/image-20220920185440531.8b0a54cd.png",u=JSON.parse('{"title":"9.20-学习http(十四)","description":"","frontmatter":{},"headers":[{"level":2,"title":"HTTP/2特性概览","slug":"http-2特性概览","link":"#http-2特性概览","children":[{"level":3,"title":"为什么不是HTTP/2.0","slug":"为什么不是http-2-0","link":"#为什么不是http-2-0","children":[]},{"level":3,"title":"兼容HTTP/1","slug":"兼容http-1","link":"#兼容http-1","children":[]},{"level":3,"title":"头部压缩","slug":"头部压缩","link":"#头部压缩","children":[]},{"level":3,"title":"二进制格式","slug":"二进制格式","link":"#二进制格式","children":[]},{"level":3,"title":"虚拟的流","slug":"虚拟的流","link":"#虚拟的流","children":[]},{"level":3,"title":"强化安全","slug":"强化安全","link":"#强化安全","children":[]},{"level":3,"title":"协议栈","slug":"协议栈","link":"#协议栈","children":[]},{"level":3,"title":"小结","slug":"小结","link":"#小结","children":[]}]},{"level":2,"title":"参考","slug":"参考","link":"#参考","children":[]}],"relativePath":"article/daily-study/2022/september/9.20-学习http(十四).md"}'),n={name:"article/daily-study/2022/september/9.20-学习http(十四).md"},l=a('<h1 id="_9-20-学习http-十四" tabindex="-1">9.20-学习http(十四) <a class="header-anchor" href="#_9-20-学习http-十四" aria-hidden="true">#</a></h1><h2 id="http-2特性概览" tabindex="-1"><strong>HTTP/2特性概览</strong> <a class="header-anchor" href="#http-2特性概览" aria-hidden="true">#</a></h2><h3 id="为什么不是http-2-0" tabindex="-1"><strong>为什么不是HTTP/2.0</strong> <a class="header-anchor" href="#为什么不是http-2-0" aria-hidden="true">#</a></h3><p>为什么 HTTP/2 不像之前的1.0、1.1那样叫2.0呢?</p><p>这个也是很多初次接触 HTTP/2 的人问的最多的一个问题，对此 HTTP/2 工作组特别给出了解释。</p><p>他们认为以前的1.0、1.1造成了很多的混乱和误解，让人在实际的使用中难以区分差异，所以就决定 HTTP 协议不再使用小版本号(minor version)，只使用大版本号 (major version)，从今往后 HTTP 协议不会出现 HTTP/2.0、2.1，只会 有HTTP/2、HTTP/3......</p><p>这样就可以明确无误地辨别出协议版本的跃进程度，让协议在一段较长的时期内保持稳定，每当发布新版本的 HTTP 协议都会有本质的不同，绝不会有零敲碎打的小改良。</p><h3 id="兼容http-1" tabindex="-1"><strong>兼容HTTP/1</strong> <a class="header-anchor" href="#兼容http-1" aria-hidden="true">#</a></h3><p>由于 HTTPS 已经在安全方面做的非常好了，所以 HTTP/2 的唯一目标就是改进性能。</p><p>但它不仅背负着众多的期待，同时还背负着 HTTP/1 庞大的历史包袱，所以协议的修改必须小心谨慎，兼容性是首要考虑的目标，否则就会破坏互联网上无数现有的资产，这方面 TLS 已经有了先例(为了兼容 TLS1.2 不得不进行伪装)。</p><p>那么，HTTP/2 是怎么做的呢?</p><p>因为必须要保持功能上的兼容，所以 HTTP/2 把 HTTP 分解成了语义和语法两个部分，语义层不做改动，与 HTTP/1 完全一致(即 RFC7231)。比如请求方法、 URI、状态码、头字段等概念都保留不变，这样就消除了再学习的成本，基于 HTTP 的上层应用也不需要做任何修改，可以无缝转换到 HTTP/2。</p><p>特别要说的是，与 HTTPS 不同，HTTP/2 没有在 URI 里引入新的协议名，仍然用http表示明文协议，用https表示加密协议。</p><p>这是一个非常了不起的决定，可以让浏览器或者服务器去自动升级或降级协议，免去了选择的麻烦，让用户在上网的时候都意识不到协议的切换，实现平滑过渡。</p><p>在语义保持稳定之后，HTTP/2 在语法层做了天翻地覆的改造，完全变更了 HTTP 报文的传输格式。</p><h3 id="头部压缩" tabindex="-1"><strong>头部压缩</strong> <a class="header-anchor" href="#头部压缩" aria-hidden="true">#</a></h3><p>HTTP/1 里可以用头字段Content-Encoding指定 Body 的编码方式，比如用 gzip 压缩来节约带宽，但报文的另一个组成部—Header 却被无视了，没有针对它的优化手段。</p><p>由于报文 Header 一般会携带User Agent、Cookie、Accept、Server等许多固定的头字段，多达几百字节甚至上千字节，但 Body 却经常只有几十字节(比如 GET 请求、204/301/304 响应)，成了不折不扣的大头儿子。更要命的是，成千上万的请求响应报文里有很多字段值都是重复的，非常浪费，长尾效应导致大量带宽消耗在了这些 冗余度极高的数据上。</p><p>所以，HTTP/2 把<strong>头部压缩</strong>作为性能改进的一个重点，优化的方式你也肯定能想到，还是压缩。</p><p>不过 HTTP/2 并没有使用传统的压缩算法，而是开发了专门的<strong>HPACK</strong>算法，在客户端和服务器两端建立字典，用索引号表示重复的字符串，还釆用哈夫曼编码来压缩整数和 字符串，可以达到 50%~90% 的高压缩率。</p><h3 id="二进制格式" tabindex="-1"><strong>二进制格式</strong> <a class="header-anchor" href="#二进制格式" aria-hidden="true">#</a></h3><p>你可能已经很习惯于 HTTP/1 里纯文本形式的报文了，它的优点是一目了然，用最简单的工具就可以开发调试，非常方便。</p><p>但 HTTP/2 在这方面没有妥协，决定改变延续了十多年的现状，不再使用肉眼可见的 ASCII 码，而是向下层的 TCP/IP 协议靠拢，全面采用二进制格式。</p><p>这样虽然对人不友好，但却大大方便了计算机的解析。原来使用纯文本的时候容易出现多义性，比如大小写、空白字符、回车换行、多字少字等等，程序在处理时必须用复杂的状态机，效率低，还麻烦。</p><p>而二进制里只有0和1，可以严格规定字段大小、顺序、标志位等格式，对就是对，错就是错，解析起来没有歧义，实现简单，而且体积小、速度快，做到内部提 效。</p><p>以二进制格式为基础，HTTP/2 就开始了大刀阔斧的改革。</p><p>它把 TCP 协议的部分特性挪到了应用层，把原来的Header+Body的消息打散为数个小片的<strong>二进制帧</strong>(Frame)，用HEADERS帧存放头数据、DATA帧存放实体数据。</p><p>这种做法有点像是Chunked分块编码的方式，也是化整为零的 思路，但 HTTP/2 数据分帧后Header+Body的报文结构就完全消失了，协议看到的只是一个个的碎片。</p><img src="'+i+'" alt="image-20220920185440531" style="zoom:50%;"><h3 id="虚拟的流" tabindex="-1"><strong>虚拟的流</strong> <a class="header-anchor" href="#虚拟的流" aria-hidden="true">#</a></h3><p>消息的碎片到达目的地后应该怎么组装起来呢?</p><p>HTTP/2 为此定义了一个<strong>流</strong>(Stream)的概念，<strong>它是二进制帧的双向传输序列</strong>，同一个消息往返的帧会分配一个唯一的流 ID。你可以想象把它成是一个虚拟的数据流，在里面流动的是一串有先后顺序的数据帧，这些数据帧按照次序组装起来就是 HTTP/1 里的 请求报文和响应报文。</p><p>因为流是虚拟的，实际上并不存在，所以 HTTP/2 就可以在一个 TCP 连接上用<strong>流</strong>同时发送多个碎片化的消息，这就是常说的<strong>多路复用</strong>( Multiplexing) =&gt;多个往返通信都复用一个连接来处理。</p><p>在流的层面上看，消息是一些有序的帧序列，而在连接的层面上看，消息却是乱序收发的帧。多个请求 / 响应之间没有了顺序关系，不需要排队等待，也就不会再 出现队头阻塞问题，降低了延迟，大幅度提高了连接的利用率。</p><p>为了更好地利用连接，加大吞吐量，HTTP/2 还添加了一些控制帧来管理虚拟的流，实现了优先级和流量控制，这些特性也和 TCP 协议非常相似。</p><p>HTTP/2 还在一定程度上改变了传统的请求 - 应答工作模式，服务器不再是完全被动地响应请求，也可以新建流主动向客户端发送消息。比如，在浏览器刚请求 HTML 的时 候就提前把可能会用到的 JS、CSS 文件发给客户端，减少等待的延迟，这被称为<strong>服务推送</strong>(Server Push，也叫 Cache Push)。</p><h3 id="强化安全" tabindex="-1"><strong>强化安全</strong> <a class="header-anchor" href="#强化安全" aria-hidden="true">#</a></h3><p>出于兼容的考虑，HTTP/2 延续了 HTTP/1 的明文特点，可以像以前一样使用明文传输数据，不强制使用加密通信，不过格式还是二进制，只是不需要解密。</p><p>但由于 HTTPS 已经是大势所趋，而且主流的浏览器 Chrome、Firefox 等都公开宣布只支持加密的 HTTP/2，所以事实上的 HTTP/2 是加密的。也就是说，互联网上通常所能见 到的 HTTP/2 都是使用https协议名，跑在 TLS 上面。</p><p>为了区分加密和明文这两个不同的版本，HTTP/2 协议定义了两个字符串标识符:h2表示加密的 HTTP/2，h2c表示明文的 HTTP/2，多出的那个字母c的 意思是clear text。</p><p>在 HTTP/2 标准制定的时候(2015 年)已经发现了很多 SSL/TLS 的弱点，而新的 TLS1.3 还未发布，所以加密版本的 HTTP/2 在安全方面做了强化，要求下层的通信协议必须是 TLS1.2 以上，还要支持前向安全和 SNI，并且把几百个弱密码套件列入了黑名单，比 如 DES、RC4、CBC、SHA-1 都不能在 HTTP/2 里使用，相当于底层用的是TLS1.25。</p><h3 id="协议栈" tabindex="-1"><strong>协议栈</strong> <a class="header-anchor" href="#协议栈" aria-hidden="true">#</a></h3><p>下面的这张图对比了 HTTP/1、HTTPS 和 HTTP/2 的协议栈，你可以清晰地看到，HTTP/2 是建立在HPackStreamTLS1.2基础之上的，比 HTTP/1、HTTPS 复杂了一 些。</p><img src="'+e+'" alt="image-20220920185724360" style="zoom:50%;"><p>虽然 HTTP/2 的底层实现很复杂，但它的语义还是简单的 HTTP/1，之前学习的知识不会过时，仍然能够用得上。</p><h3 id="小结" tabindex="-1"><strong>小结</strong> <a class="header-anchor" href="#小结" aria-hidden="true">#</a></h3><ul><li>HTTP 协议取消了小版本号，所以 HTTP/2 的正式名字不是 2.0</li><li>HTTP/2 在语义上兼容 HTTP/1，保留了请求方法、URI 等传统概念</li><li>HTTP/2 使用HPACK算法压缩头部信息，消除冗余数据节约带宽</li><li>HTTP/2 的消息不再是Header+Body的形式，而是分散为多个二进制帧</li><li>HTTP/2 使用虚拟的流传输消息，解决了困扰多年的队头阻塞问题，同时实现了多路复用，提高连接的利用率</li><li>HTTP/2 也增强了安全性，要求至少是 TLS1.2，而且禁用了很多不安全的密码套件</li></ul><p><strong>HTTP/2.0</strong> 相比较 <strong>HTTP/1.1</strong></p><ul><li>二进制协议，不再是纯文本(<code>二进制协议</code>)</li><li>可发起多个请求，废弃了 1.1 里的管道(<code>多路复用</code>)</li><li>使用专用算法压缩头部，减少数据传输量(<code>头部压缩, 使得可以在header带更多数据了</code>)</li><li>允许服务器主动向客户端推送数据(<code>服务器主动push数据到客户端</code>)</li><li>增强了安全性，事实上要求加密通信(<code>安全性</code>)</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-hidden="true">#</a></h2><p><a href="https://time.geekbang.org/column/intro/100029001" target="_blank" rel="noreferrer">透视HTTP协议(罗剑锋)</a></p>',51),p=[l];function s(h,o,d,P,H,c){return r(),T("div",null,p)}const S=t(n,[["render",s]]);export{u as __pageData,S as default};
